&apos;) file2.append(content[56:]) content = f.readline().decode()diff = difflib.Differ().compare(file1, file2)l1, l2, common = [], [], []for line in diff: if line[0] == &apos;-&apos;: l1.append(line[2:-1]) elif line[0] == &apos;+&apos;: l2.append(line[2:-1]) else: common.append(line[2:-1])print(f&quot;l1: {l1}&quot;)print(f&quot;l2: {l2}&quot;)print(f&quot;common: {common}&quot;) 得到结果 l1: [&apos;89 50 4e 47 0d 0a 1a 0a ...]l2: [&apos;89 50 4e 47 0d 0a 1a 0a ...]common: [&apos;89 50 4e 47 0d 0a 1a 0a ...] 熟悉png文件结构的话已经看出比对出的三个结果应该怎么处理了。 三个结果起始的八个字节正是png文件的文件头(signature)-&gt;source 下面将三个结果分别存储为png文件，即得到下一题的地址、账号与密码。 123456789with open(&apos;assets/lvl18_1.png&apos;, &apos;wb&apos;) as f1: for line in l1: f1.write(bytes([int(o, 16) for o in line.split(&quot; &quot;) if o]))with open(&apos;assets/lvl18_2.png&apos;, &apos;wb&apos;) as f2: for line in l2: f2.write(bytes([int(o, 16) for o in line.split(&quot; &quot;) if o]))with open(&apos;assets/lvl18_3.png&apos;, &apos;wb&apos;) as f3: for line in common: f3.write(bytes([int(o, 16) for o in line.split(&quot; &quot;) if o])) #Level 19一张印度地图，以及网页注释中的一封邮件 看样子是要处理音频？而且说明了用base64进行编码，要用的自然就是base64.b64decode()了 123456import base64with open(&quot;assets/txt_for_19.txt&quot;, &quot;r&quot;) as f: content = f.read()audio = base64.b64decode(content)with open(&quot;assets/indian.wav&quot;, &apos;wb&apos;) as f: f.write(audio) 得到音频为 Sorry! 改地址试一下 &quot;what are you apologizing for?&quot; 看上去不对，有被忽略的线索。 对音频信息不是很了解，正好借刚刚的indian.wav这个文件学习一下wave模块和相关的参数含义 12345import wavewith wave.open(&apos;assets/indian.wav&apos;, &apos;rb&apos;) as sound: params = sound.getparams()print(params) _wave_params(nchannels=1, sampwidth=2, framerate=11025, nframes=55788, comptype=&apos;NONE&apos;, compname=&apos;not compressed&apos;) 大概是：单声道，采样率2byte，帧率11025hz，共55788帧，无压缩 注意到图片中陆地颜色和海洋颜色相反，reverse？尝试将音频整体翻转 12345678import wavewith wave.open(&apos;assets/indian.wav&apos;, &apos;rb&apos;) as sound: params = sound.getparams() content = sound.readframes(sound.